org.machanism.macha.core.commons.configurator.Configurator config = null;
org.machanism.machai.bindex.Picker picker = new org.machanism.machai.bindex.Picker("openai", null, config);
picker.setScore(java.lang.Double.valueOf(0.88d));
java.util.List<org.machanism.machai.schema.Bindex> matches = picker.pick("Find a Java library for Bindex registration and semantic search in MongoDB");
for (org.machanism.machai.schema.Bindex match : matches) {
    java.lang.System.out.println(match.getId() + " -> " + match.getName());
}
